    setInsight(null);
    // Set default tab based on stage
    if (client.stage === ClientStage.PROSPECT) {
      setActiveTab('prospect');
    } else if (client.stage === ClientStage.CHURN) {
      setActiveTab('churn');
    } else {
      setActiveTab('performance');
    }
  }, [client.id]);

  const handleGenerateInsight = async () => {
    setLoadingInsight(true);
    try {
      const data = await generateClientInsight(client);
      setInsight(data);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingInsight(false);
    }
