    }
    return (
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Creative DNA */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Sparkles size={18} className="text-indigo-600"/> 素材创意 DNA</h3>

             <div className="grid grid-cols-2 gap-4 mb-6">
                 <div className="bg-gray-50 p-3 rounded-lg">
                    <div className="text-xs text-gray-500">平均衰退周期</div>
                    <div className="font-semibold text-gray-900">{client.creativeStats?.lifecycleDays || '-'} 天</div>
                 </div>
                 <div className="bg-gray-50 p-3 rounded-lg">
                    <div className="text-xs text-gray-500">拒审率</div>
                    <div className="font-semibold text-gray-900">{client.creativeStats?.rejectionRate || 0}%</div>
                 </div>
             </div>

             <div className="mb-4">
                 <div className="text-sm text-gray-600 mb-2">Top 跑量素材</div>
                 <div className="space-y-3">
                    {client.creativeStats?.topCreatives.map(c => (
                        <div key={c.id} className="flex items-center gap-3 p-2 border border-gray-100 rounded-lg hover:bg-gray-50">
                            <img src={c.url} className="w-16 h-10 object-cover rounded bg-gray-200" alt={c.name}/>
                            <div className="flex-1">
                                <div className="text-sm font-medium truncate">{c.name}</div>
                                <div className="text-xs text-gray-500 capitalize">{c.type} • CTR {c.ctr}%</div>
                            </div>
                        </div>
                    ))}
                    {!client.creativeStats && <div className="text-gray-400 text-sm">暂无数据</div>}
                 </div>
             </div>

             <div>
                <div className="text-sm text-gray-600 mb-2">偏好标签</div>
                <div className="flex flex-wrap gap-2">
                    {client.creativeStats?.tags.map(tag => (
                        <span key={tag} className="px-2 py-1 bg-violet-50 text-violet-700 text-xs rounded border border-violet-100">{tag}</span>
                    ))}
                </div>
             </div>
        </div>

        {/* App Product Health */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Smartphone size={18} className="text-indigo-600"/> 应用产品健康度</h3>

             <div className="flex items-center gap-4 mb-6">
                 <div className="text-4xl font-bold text-gray-900">{client.appHealth?.storeRating || 'N/A'}</div>
                 <div className="flex flex-col">
                    <div className="flex text-yellow-400">★★★★☆</div>
                    <span className="text-xs text-gray-500">应用商店评分</span>
                 </div>
             </div>

             <div className="space-y-4">
                 <div>
                    <div className="flex justify-between text-sm mb-1">
                        <span className="text-gray-600">崩溃率 (Crash Rate)</span>
                        <span className={`${(client.appHealth?.crashRate || 0) > 1 ? 'text-red-500' : 'text-green-600'}`}>{client.appHealth?.crashRate || 0}%</span>
                    </div>
                    <div className="w-full bg-gray-100 rounded-full h-2">
                        <div className="bg-gray-400 h-2 rounded-full" style={{width: `${(client.appHealth?.crashRate || 0) * 20}%`}}></div>
                    </div>
                 </div>

                 <div>
                    <div className="flex justify-between text-sm mb-1">
                        <span className="text-gray-600">包体大小</span>
                        <span>{client.appHealth?.packageSizeMB || '-'} MB</span>
                    </div>
                    <div className="text-xs text-gray-400">包体过大可能会降低 15% 的转化率</div>
                 </div>

                 <div className="pt-4 border-t border-gray-100">
                    <span className="text-sm font-medium text-gray-700 block mb-2">高频负面舆情</span>
                    <div className="flex gap-2">
                        {client.appHealth?.negativeSentimentKeywords.map(k => (
                             <span key={k} className="px-2 py-1 bg-red-50 text-red-600 text-xs rounded border border-red-100">{k}</span>
                        ))}
                    </div>
                 </div>
             </div>
        </div>
      </div>
    );
  };

  const renderAudienceGrowthTab = () => {
    if (!client.audienceData) {
        return renderEmptyState("暂无人群或增长机会数据");
    }
    return (
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Audience Profile */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Users size={18} className="text-indigo-600"/> 人群画像与渗透</h3>

             <div className="mb-6">
                 <div className="flex justify-between items-end mb-2">
                     <span className="text-sm text-gray-600">核心人群渗透率</span>
                     <span className="text-xl font-bold text-indigo-600">{client.audienceData?.penetrationRate || 0}%</span>
                 </div>
                 <div className="w-full bg-gray-100 rounded-full h-3">
                     <div className="bg-indigo-600 h-3 rounded-full" style={{width: `${client.audienceData?.penetrationRate || 0}%`}}></div>
                 </div>
                 <div className="text-xs text-gray-500 mt-2 text-right">仍有大量蓝海人群未触达</div>
             </div>

             <div className="mb-6">
                 <div className="text-sm text-gray-600 mb-3">已获客特征</div>
                 <div className="space-y-2">
                     {client.audienceData?.demographics.map((demo, i) => (
                         <div key={i} className="flex items-center text-sm">
                             <span className="w-20 text-gray-500">{demo.label}</span>
                             <div className="flex-1 h-2 bg-gray-100 rounded-full mx-2">
                                 <div className="h-2 bg-blue-400 rounded-full" style={{width: `${demo.value}%`}}></div>
                             </div>
                             <span className="text-gray-700 font-medium">{demo.value}%</span>
                         </div>
                     ))}
                     {!client.audienceData && <div className="text-gray-400 text-sm">暂无数据</div>}
                 </div>
             </div>

             <div className="p-3 bg-gray-50 rounded-lg flex justify-between items-center">
                 <span className="text-sm text-gray-600">竞品人群重合度</span>
                 <span className="font-bold text-gray-800">{client.audienceData?.competitorOverlap || 0}%</span>
             </div>
          </div>

          {/* Growth Opportunity */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
             <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-4"><Zap size={18} className="text-indigo-600"/> 增长机会诊断</h3>

             <div className="space-y-4">
                 <div className="border-l-4 border-yellow-400 pl-4 py-1">
                     <h4 className="text-sm font-bold text-gray-800 mb-2">推荐蓝海词包</h4>
                     <ul className="space-y-1">
                         {client.growthOpp?.recommendedKeywords.map((k, i) => (
                             <li key={i} className="text-sm flex justify-between">
                                 <span className="text-gray-600">{k.keyword}</span>
                                 <span className="text-xs bg-green-100 text-green-700 px-2 rounded">竞争: {k.competition}</span>
                             </li>
                         ))}
                     </ul>
                 </div>

                 <div className="border-l-4 border-blue-400 pl-4 py-1">
                     <h4 className="text-sm font-bold text-gray-800 mb-2">未投版位机会</h4>
                      <ul className="space-y-1">
                         {client.growthOpp?.missedPlacements.map((p, i) => (
                             <li key={i} className="text-sm flex justify-between">
                                 <span className="text-gray-600">{p.name}</span>
                                 <span className="text-xs font-bold text-blue-600">预估提升 {p.potentialLift}</span>
                             </li>
                         ))}
                     </ul>
                 </div>

                 <div className="mt-4 pt-4 border-t border-gray-100">
                     <h4 className="text-xs text-gray-500 uppercase font-semibold mb-2">行业趋势对标</h4>
                     <div className="flex gap-2 flex-wrap">
                         {client.growthOpp?.industryTrends.map((t, i) => (
                             <span key={i} className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-full flex items-center gap-1">
                                 <TrendingUp size={10} /> {t}
                             </span>
                         ))}
                     </div>
                 </div>
             </div>
          </div>
      </div>
    );
  };

  const renderChurnTab = () => {
      // Logic: If already churned, show analysis. If active, show risk monitoring.
      if (client.stage === ClientStage.CHURN) {
          return (
            <div className="space-y-6">
                <div className="bg-red-50 border border-red-100 rounded-xl p-6 flex flex-col md:flex-row gap-6 items-start">
                    <div className="p-3 bg-white rounded-full shadow-sm text-red-500">
                    <AlertTriangle size={32} />
                    </div>
                    <div className="flex-1">
                    <h3 className="text-xl font-bold text-red-800 mb-2">已流失: 风险评分 {client.riskScore}/100</h3>
                    <p className="text-red-700 mb-4">
                        该广告主自 {client.lastActiveDate} 起停止投放。 
                        主要原因: <strong>{client.churnReason}</strong>。
                    </p>
                    <div className="bg-white/60 rounded-lg p-4">
                        <h4 className="font-semibold text-red-800 mb-2">建议挽回措施:</h4>
                        <ul className="list-disc list-inside space-y-1 text-sm text-red-800">
                        {client.retentionPlan?.map((plan, i) => (
                            <li key={i}>{plan}</li>
                        ))}
                        </ul>
                    </div>
                    </div>
                </div>
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 mb-4">下滑分析 (流失前6个月)</h3>
                    <TrendChart data={client.spendTrend || []} dataKey="churn" color="#ef4444" />
                </div>
            </div>
          );
      } else {
          // Active or Prospect - Show Risk Monitoring
          return (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-6">
                        <ShieldAlert size={18} className="text-orange-500"/> 风控合规监测
                    </h3>
                    <div className="space-y-6">
                        <div className="flex justify-between items-center p-4 bg-gray-50 rounded-lg">
                            <span className="text-gray-600 text-sm">欺诈评分 (Fraud Score)</span>
                            <div className="text-right">
                                <div className={`text-xl font-bold ${client.riskProfile?.fraudScore && client.riskProfile.fraudScore > 50 ? 'text-red-600' : 'text-green-600'}`}>
                                    {client.riskProfile?.fraudScore || 0}
                                </div>
                                <div className="text-xs text-gray-400">0-100 (分数越高风险越大)</div>
                            </div>
                        </div>
                        <div className="flex justify-between items-center p-4 bg-gray-50 rounded-lg">
                            <span className="text-gray-600 text-sm">历史违规次数</span>
                            <span className="font-medium text-gray-900">{client.riskProfile?.violationCount || 0} 次</span>
                        </div>
                        <div className="flex justify-between items-center p-4 bg-gray-50 rounded-lg">
                            <span className="text-gray-600 text-sm">关联封禁账户</span>
                            <span className="font-medium text-gray-900">{client.riskProfile?.relatedBannedAccounts || 0} 个</span>
                        </div>
                    </div>
                </div>

                <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
                    <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2 mb-6">
                        <Wallet size={18} className="text-orange-500"/> 财务健康度
                    </h3>
                     <div className="space-y-6">
                        <div className="flex justify-between items-center">
                            <span className="text-gray-600 text-sm">账户模式</span>
                            <span className="px-3 py-1 bg-blue-50 text-blue-700 text-xs rounded-full font-medium">
                                {client.financialHealth?.paymentMode || 'Prepay'}
                            </span>
                        </div>
                        <div>
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-gray-600 text-sm">余额预计支撑天数</span>
                                <span className="text-xl font-bold text-gray-900">{client.financialHealth?.walletRunwayDays || 0} 天</span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-2">
                                <div className={`h-2 rounded-full ${(client.financialHealth?.walletRunwayDays || 0) < 7 ? 'bg-red-500' : 'bg-green-500'}`} 
                                     style={{width: `${Math.min((client.financialHealth?.walletRunwayDays || 0) * 5, 100)}%`}}></div>
                            </div>
                            {(client.financialHealth?.walletRunwayDays || 0) < 7 && (
                                <p className="text-xs text-red-500 mt-2 flex items-center gap-1">
                                    <AlertTriangle size={10} /> 建议立即提醒充值
                                </p>
                            )}
                        </div>
                        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-gray-100">
                             <div>
                                <div className="text-xs text-gray-500 mb-1">退款率</div>
                                <div className="font-medium text-gray-900">{client.financialHealth?.refundRate || 0}%</div>
                             </div>
                             <div>
                                <div className="text-xs text-gray-500 mb-1">逾期记录</div>
                                <div className="font-medium text-gray-900">{client.financialHealth?.overdueHistory || 0} 次</div>
                             </div>
                        </div>
                    </div>
                </div>
            </div>
          );
      }
  };

  return (
    <div className="max-w-7xl mx-auto pb-12">
      {renderHeader()}

      {/* Insight Section - Always Visible if generated */}
      <div className="mb-8">
        {!insight ? (
          <button 
            onClick={handleGenerateInsight}
            disabled={loadingInsight}
            className="flex items-center gap-2 bg-gradient-to-r from-violet-600 to-indigo-600 text-white px-5 py-3 rounded-lg shadow-md hover:shadow-lg transition-all disabled:opacity-70"
          >
            {loadingInsight ? (
               <>正在生成 AI 分析...</>
            ) : (
               <><Sparkles size={18} /> 生成 AI 战略洞察</>
            )}
          </button>
        ) : (
          <div className="bg-gradient-to-r from-violet-50 to-indigo-50 border border-indigo-100 rounded-xl p-6 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10 text-indigo-900">
                <BrainCircuit size={120} />
             </div>
             <h3 className="text-lg font-bold text-indigo-900 mb-3 flex items-center gap-2">
                <Sparkles size={18} className="text-indigo-600"/> AI 战略分析
             </h3>
             <p className="text-indigo-800 font-medium mb-4">{insight.summary}</p>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">行动建议</h4>
                    <ul className="space-y-2">
                        {insight.actionItems.map((item, i) => (
                            <li key={i} className="flex items-start gap-2 text-sm text-indigo-900">
                                <span className="mt-1 w-1.5 h-1.5 bg-indigo-500 rounded-full flex-shrink-0"></span>
                                {item}
                            </li>
                        ))}
                    </ul>
                </div>
                <div>
                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-wider mb-2">AI 预测</h4>
                    <p className="text-sm text-indigo-900 italic">"{insight.prediction}"</p>
                </div>
             </div>
             <button onClick={() => setInsight(null)} className="mt-4 text-xs text-indigo-500 hover:text-indigo-700 underline">刷新分析</button>
          </div>
        )}
      </div>

      {/* Unified Tab Navigation */}
      <div>
        <div className="flex border-b border-gray-200 mb-6 overflow-x-auto scrollbar-hide">
            {[
                { id: 'prospect', label: '拓展进度', icon: <Briefcase size={16}/> },
                { id: 'performance', label: '分发分析', icon: <BarChart2 size={16}/> },
                { id: 'creative', label: '素材与产品', icon: <Sparkles size={16}/> },
                { id: 'audience', label: '人群与增长', icon: <Users size={16}/> },
                { id: 'churn', label: '流失预测', icon: <AlertTriangle size={16}/> },
            ].map(tab => (
                 <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`flex items-center gap-2 px-5 py-3 text-sm font-medium whitespace-nowrap border-b-2 transition-colors
                        ${activeTab === tab.id 
                            ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' 
                            : 'border-transparent text-gray-500 hover:text-gray-700 hover:bg-gray-50'
                        }`}
                >
                    {tab.icon}
                    {tab.label}
                </button>
            ))}
        </div>

        {/* Tab Content */}
        <div className="min-h-[400px]">
            {activeTab === 'prospect' && renderProspectTab()}
            {activeTab === 'performance' && renderPerformanceTab()}
            {activeTab === 'creative' && renderCreativeProductTab()}
            {activeTab === 'audience' && renderAudienceGrowthTab()}
            {activeTab === 'churn' && renderChurnTab()}
        </div>
      </div>
    </div>
  );
};
